arguments.file_text:
namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and human civilization." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds three patents.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor", Bio = "Dr. Martinez focuses on discrete mathematics and combinatorics. He received the University Teaching Excellence Award in 2024.", Email = "rmartinez@university.edu" },
            new() { Id = 3, Name = "Prof. Sarah Williams", Title = "Professor", Bio = "Prof. Williams is a published author and literary critic specializing in contemporary American fiction.", Email = "swilliams@university.edu" },
            new() { Id = 4, Name = "Dr. James Okafor", Title = "Assistant Professor", Bio = "Dr. Okafor researches quantum mechanics and particle physics. He previously worked at CERN.", Email = "jokafor@university.edu" },
            new() { Id = 5, Name = "Dr. Emily Park", Title = "Professor", Bio = "Dr. Park is a historian of early modern Europe with expertise in the Renaissance and Reformation periods.", Email = "epark@university.edu" },
            new() { Id = 6, Name = "Dr. Michael Torres", Title = "Associate Professor", Bio = "Dr. Torres specializes in software engineering and distributed systems. He spent 10 years in industry before joining academia.", Email = "mtorres@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "Foundational concepts in computing including programming basics, data types, control structures, and problem-solving strategies.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "Advanced study of data organization including trees, graphs, hash tables, and algorithm analysis with Big-O notation.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[5] },
            new() { Id = 3, Code = "CS 450", Title = "Machine Learning", Description = "Introduction to supervised and unsupervised learning, neural networks, and practical applications of AI.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and engineering.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1] },
            new() { Id = 5, Code = "MATH 301", Title = "Discrete Mathematics", Description = "Logic, set theory, combinatorics, graph theory, and mathematical reasoning for computer science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 6, Code = "ENG 101", Title = "College Writing", Description = "Develop critical reading and writing skills through analysis of diverse texts and structured essay composition.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2] },
            new() { Id = 7, Code = "ENG 350", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, with emphasis on cultural context.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2] },
            new() { Id = 8, Code = "PHYS 201", Title = "Classical Mechanics", Description = "Newtonian mechanics, energy, momentum, rotational dynamics, and oscillations.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3] },
            new() { Id = 9, Code = "PHYS 401", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = true },
