@page "/courses"
@rendermode InteractiveServer

@inject CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses, instructors..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id">@dept.Code — @dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var courses = CatalogService.SearchCourses(searchTerm, selectedDepartmentId);
}

<p class="text-muted">Showing @courses.Count course(s)</p>

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Code</th>
            <th>Title</th>
            <th>Department</th>
            <th>Credits</th>
            <th>Instructor</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var course in courses)
        {
            <tr>
                <td>@course.Code</td>
                <td>@course.Title</td>
                <td>@course.Department.Name</td>
                <td>@course.Credits</td>
                <td>@course.Instructor.Name</td>
                <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
            </tr>
        }
    </tbody>
</table>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}

@code {
    private string? searchTerm;
    private int selectedDepartmentId;
}

@page "/courses/{Id:int}"

@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p><strong>@course.Schedule</strong></p>

            <h4 class="mt-4">Credits</h4>
            <p><span class="badge bg-primary fs-6">@course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6>@course.Instructor.Name</h6>
                    <p class="text-muted">@course.Instructor.Title</p>
                    <p>@course.Instructor.Bio</p>
                    <p><a href="mailto:@course.Instructor.Email">@course.Instructor.Email</a></p>
                </div>
            </div>
            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"

@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Your enrollment request has been received. You will be notified once it has been processed.</p>
        <a href="courses" class="btn btn-primary">Back to Courses</a>
    </div>
}
else
{
    if (error)
    {
        <div class="alert alert-danger">Please fill out all fields and select a valid course.</div>
    }

    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
        <AntiforgeryToken />

        <div class="mb-3" style="max-width: 400px;">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                   value="@Model.StudentName" required />
        </div>

        <div class="mb-3" style="max-width: 400px;">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                   value="@Model.StudentId" placeholder="e.g. S12345" required />
        </div>

        <div class="mb-3" style="max-width: 400px;">
            <label for="courseId" class="form-label">Course</label>
            <select class="form-select" id="courseId" name="Model.CourseId" required>
                <option value="0">— Select a course —</option>
                @foreach (var course in CatalogService.GetCourses())
                {
                    <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                        @course.Code — @course.Title
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? CourseId { get; set; }

    private bool submitted;
    private bool error;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (CatalogService.SubmitEnrollmentRequest(Model))
        {
            submitted = true;
            error = false;
        }
        else
        {
            error = true;
        }
    }
}

